mapper.select:
SELECT s.*, u.real_name AS studentName,
       c.course_code AS courseCode, c.course_name AS courseName
FROM sys_score s
LEFT JOIN sys_user u ON u.id = s.student_id
LEFT JOIN sys_course c ON c.id = s.course_id
WHERE s.deleted = 0
AND s.student_id = #{q.studentId}
AND s.course_id = #{q.courseId}
AND s.exam_year = #{q.examYear}
AND s.exam_term = #{q.examTerm}
AND s.status = #{q.status}

    AND (u.real_name LIKE '%' || #{q.keyword} || '%' OR c.course_name LIKE '%' || #{q.keyword} || '%')

ORDER BY s.exam_year DESC, s.exam_term DESC, s.id DESC
